const USERS = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];

app.get('/users', (req, res) => {
  res.json(USERS);
});

app.get('/users/:id', (req, res) => {
  const { id } = req.params;

  // Validate that id is a positive integer (no decimals, no leading signs, no NaN).
  if (!/^\d+$/.test(id)) {
    return res.status(400).json({
      error: 'Bad Request',
      message: `Invalid user id "${id}": id must be a positive integer.`,
    });
  }

  const numericId = Number(id);
  const user = USERS.find((u) => u.id === numericId);

  if (!user) {
    return res.status(404).json({
      error: 'Not Found',
      message: `No user found with id ${numericId}.`,
    });
  }

  res.json(user);
});

